      "english": "{3:To} ‘{0:there is no} {1:understanding} {2:for the unsteadied one’} {6:He gives} {5:the cause} {4:here} {8:by} {7:‘indriyāṇām’}. {9:Of the senses}, {10:unmastered}, {11:ranging at will} {12:in objects} {13:ranging} {14:amid}, {15:when} {16:even} {17:one single} {18:sense} {19:the mind} {20:follows after} — {21:mastered}, {22:being}, {25:goes} {24:along with} {23:that sense} — {26:then} {27:even} {28:that one} sense {35:robs} {33:the prajñā}, {34:the understanding}, {29:of a sense}, {30:of the mind} {31:or of the man}{32:,} {37:makes it} {36:scattered toward objects}. {38:How} {39:much} {40:more is to be said} when {41:many} {43:rob} {42:the prajñā}{44:!} {45:Just as} {49:the wind} {51:whirls about} {50:on every side} {48:the boat} {46:of a careless} {47:helmsman} — {52:so it is}{53:.}",
